package com.example.kafkademo.service;

import org.springframework.beans.factory.annotation.Value;
import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.kafka.support.KafkaHeaders;
import org.springframework.messaging.Message;
import org.springframework.messaging.support.MessageBuilder;
import org.springframework.stereotype.Service;

import java.util.UUID;

@Service
public class EventPublisher {

    private final KafkaTemplate<String, String> kafkaTemplate;
    private final String topic;

    public EventPublisher(
            KafkaTemplate<String, String> kafkaTemplate,
            @Value("${app.kafka.topic.events:platform.events}") String topic
    ) {
        this.kafkaTemplate = kafkaTemplate;
        this.topic = topic;
    }

    public void publish(String eventType, String payload) {
        String key = UUID.randomUUID().toString();
        Message<String> message = MessageBuilder.withPayload(payload)
                .setHeader(KafkaHeaders.TOPIC, topic)
                .setHeader(KafkaHeaders.MESSAGE_KEY, key)
                .setHeader("eventType", eventType)
                .build();

        kafkaTemplate.send(message);
    }
}

package com.example.kafkademo.web;

import com.example.kafkademo.service.EventPublisher;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.Map;

@RestController
@RequestMapping("/api/events")
public class EventController {

    private final EventPublisher publisher;

    public EventController(EventPublisher publisher) {
        this.publisher = publisher;
    }

    @PostMapping
    public ResponseEntity<Void> publish(@RequestBody Map<String, Object> body) {
        String eventType = String.valueOf(body.getOrDefault("type", "generic"));
        String payload = String.valueOf(body.getOrDefault("payload", body.toString()));
        publisher.publish(eventType, payload);
        return ResponseEntity.accepted().build();
    }
}

